// 1. 创建认证中间件
// src/dashboard/middleware/auth.middleware.ts
export interface AuthConfig {
  apiKey?: string;
  enableAuth: boolean;
}

export async function authMiddleware(config: AuthConfig) {
  return async (request: any, reply: any) => {
    // 如果禁用认证，直接通过（开发模式）
    if (!config.enableAuth) return;

    // 从 header 或 query 获取 API Key
    const apiKey = request.headers['x-api-key'] || request.query.api_key;

    // 验证 API Key
    if (!apiKey || apiKey !== config.apiKey) {
      return reply.status(401).send({
        error: 'Unauthorized',
        message: 'Invalid or missing API key'
      });
    }
  };
}

// 2. 应用到服务器
// src/dashboard/server.ts
const authConfig: AuthConfig = {
  apiKey: process.env.DASHBOARD_API_KEY || 'dev-key-change-me',
  enableAuth: process.env.DASHBOARD_ENABLE_AUTH !== 'false'
};

// 保护所有 API 路由
server.addHook('onRequest', authMiddleware(authConfig));

// WebSocket 认证
server.register(async function (fastify) {
  fastify.get('/api/ws', { websocket: true }, async (connection, req) => {
    const apiKey = new URL(req.url, `http://${req.headers.host}`)
      .searchParams.get('api_key');

    if (authConfig.enableAuth && apiKey !== authConfig.apiKey) {
      connection.socket.close(1008, 'Unauthorized');
      return;
    }
    // ... WebSocket 逻辑
  });
});
```

