```typescript
// src/dashboard/middleware/rate-limit.middleware.ts
import fp from 'fastify-plugin';
import rateLimit from '@fastify/rate-limit';

export async function setupRateLimit(server: any) {
  await server.register(rateLimit, {
    max: 100, // 每分钟最多 100 个请求
    timeWindow: '1 minute',
    cache: 10000,
    allowList: ['127.0.0.1'], // 本地无限制
    redis: undefined, // 如需分布式可用 Redis
    skipOnError: true,
    continueExceeding: false,

    // 自定义响应
    errorResponseBuilder: (req, context) => ({
      code: 429,
      error: 'Too Many Requests',
      message: `Rate limit exceeded, retry in ${context.after}`,
      retryAfter: context.after
    })
  });

  // 为写操作设置更严格的限制
  await server.register(rateLimit, {
    name: 'writeOperations',
    max: 20, // 每分钟最多 20 个写操作
    timeWindow: '1 minute',
    routes: ['/api/iterations', '/api/rollback'],
    methodWhitelist: ['GET', 'HEAD', 'OPTIONS']
  });
}
```

