// src/dashboard/middleware/validation.middleware.ts
import { ValueError } from './errors';

export function validateDto<T>(schema: {
  validate: (data: any) => T;
}) {
  return async (request: any, reply: any) => {
    try {
      request.validatedBody = schema.validate(request.body);
    } catch (error) {
      return reply.status(400).send({
        error: 'Validation Error',
        message: error.message,
        details: error.errors
      });
    }
  };
}

// 使用示例 - 迭代创建验证
export const createIterationSchema = {
  validate: (data: any) => {
    const errors: string[] = [];

    // 必填字段
    if (!data.requirement || typeof data.requirement !== 'string') {
      errors.push('requirement is required and must be a string');
    }

    // 长度限制
    if (data.requirement && data.requirement.length > 10000) {
      errors.push('requirement must be less than 10000 characters');
    }

    // 格式验证
    if (data.iterationNumber && !Number.isInteger(data.iterationNumber)) {
      errors.push('iterationNumber must be an integer');
    }

    if (errors.length > 0) {
      throw new ValueError('Validation failed', errors);
    }

    return data;
  }
};

// 应用到路由
server.post('/api/iterations', {
  preValidation: validateDto(createIterationSchema),
  handler: async (request, reply) => {
    // request.validatedBody 已验证
  }
});
```

